(function () {
  var menu = document.querySelector('.menu-btn');
  var panel = document.querySelector('.mobile-panel');
  if (menu && panel) {
    menu.addEventListener('click', function () {
      panel.classList.toggle('open');
    });
  }

  var slides = Array.prototype.slice.call(document.querySelectorAll('[data-hero-slide]'));
  var dots = Array.prototype.slice.call(document.querySelectorAll('[data-hero-dot]'));
  var current = 0;
  function showSlide(index) {
    if (!slides.length) return;
    current = (index + slides.length) % slides.length;
    slides.forEach(function (slide, i) {
      slide.classList.toggle('active', i === current);
    });
    dots.forEach(function (dot, i) {
      dot.classList.toggle('active', i === current);
    });
  }
  var prev = document.querySelector('[data-hero-prev]');
  var next = document.querySelector('[data-hero-next]');
  if (prev) prev.addEventListener('click', function () { showSlide(current - 1); });
  if (next) next.addEventListener('click', function () { showSlide(current + 1); });
  dots.forEach(function (dot) {
    dot.addEventListener('click', function () {
      showSlide(parseInt(dot.getAttribute('data-hero-dot') || '0', 10));
    });
  });
  if (slides.length > 1) {
    setInterval(function () { showSlide(current + 1); }, 5200);
  }

  var list = document.querySelector('[data-filter-list]');
  var listSearch = document.querySelector('[data-list-search]');
  var activeYear = '';
  function filterList() {
    if (!list) return;
    var q = listSearch ? listSearch.value.trim().toLowerCase() : '';
    Array.prototype.slice.call(list.children).forEach(function (item) {
      var hay = [item.getAttribute('data-title'), item.getAttribute('data-year'), item.getAttribute('data-region'), item.getAttribute('data-genre')].join(' ').toLowerCase();
      var year = item.getAttribute('data-year') || '';
      var okText = !q || hay.indexOf(q) !== -1;
      var okYear = !activeYear || year === activeYear;
      item.classList.toggle('hidden-by-filter', !(okText && okYear));
    });
  }
  if (listSearch) listSearch.addEventListener('input', filterList);
  Array.prototype.slice.call(document.querySelectorAll('[data-filter-year]')).forEach(function (btn) {
    btn.addEventListener('click', function () {
      activeYear = btn.getAttribute('data-filter-year') || '';
      Array.prototype.slice.call(document.querySelectorAll('[data-filter-year]')).forEach(function (b) { b.classList.remove('active'); });
      btn.classList.add('active');
      filterList();
    });
  });

  function initSearchPage() {
    var input = document.getElementById('searchInput');
    var results = document.getElementById('searchResults');
    var summary = document.getElementById('searchSummary');
    if (!input || !results) return;
    var params = new URLSearchParams(window.location.search);
    var q = params.get('q') || '';
    input.value = q;
    function render(term) {
      var value = term.trim().toLowerCase();
      var data = window.SITE_INDEX || [];
      var matched = value ? data.filter(function (item) {
        return [item.title, item.year, item.region, item.type, item.genre, item.category, (item.tags || []).join(' '), item.summary].join(' ').toLowerCase().indexOf(value) !== -1;
      }).slice(0, 120) : data.slice(0, 60);
      summary.textContent = value ? '搜索结果' : '热门内容';
      results.innerHTML = matched.map(function (item) {
        return '<article class="search-item"><a href="' + item.url + '"><img src="' + item.image + '" alt="' + escapeHtml(item.title) + '"></a><div><h2><a href="' + item.url + '">' + escapeHtml(item.title) + '</a></h2><p>' + escapeHtml(item.summary) + '</p><div class="card-meta"><span>' + escapeHtml(item.year) + '</span><span>' + escapeHtml(item.region) + '</span><span>' + escapeHtml(item.category) + '</span></div></div><a class="rank-play" href="' + item.url + '">观看</a></article>';
      }).join('');
    }
    input.addEventListener('input', function () { render(input.value); });
    render(q);
  }

  function escapeHtml(value) {
    return String(value || '').replace(/[&<>"']/g, function (char) {
      return { '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[char];
    });
  }

  function initPlayers() {
    Array.prototype.slice.call(document.querySelectorAll('.player-stage')).forEach(function (stage) {
      var video = stage.querySelector('video');
      var overlay = stage.querySelector('.player-overlay');
      var stream = stage.getAttribute('data-v');
      var ready = false;
      function attach() {
        if (!video || !stream) return;
        if (ready) return;
        ready = true;
        if (window.Hls && window.Hls.isSupported()) {
          var hls = new window.Hls();
          hls.loadSource(stream);
          hls.attachMedia(video);
        } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
          video.src = stream;
        } else {
          video.src = stream;
        }
      }
      function playNow() {
        attach();
        if (overlay) overlay.classList.add('hide');
        var promise = video.play();
        if (promise && promise.catch) promise.catch(function () {});
      }
      if (overlay) overlay.addEventListener('click', playNow);
      if (video) video.addEventListener('click', function () {
        if (video.paused) playNow();
      });
    });
  }

  initSearchPage();
  initPlayers();
})();
